SELECT /* base.sy :: SyVendorUser :: selectList */ u.* , ste.site_nm AS site_nm , vnd.vendor_nm AS vendor_nm , usr.user_nm AS user_nm , cd_p.code_label AS position_cd_nm , cd_vms.code_label AS vendor_user_status_cd_nm FROM sy_vendor_user u LEFT JOIN sy_site ste ON ste.site_id = u.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = u.vendor_id LEFT JOIN sy_user usr ON usr.user_id = u.user_id LEFT JOIN sy_code cd_p ON cd_p.code_grp = 'POSITION' AND cd_p.code_value = u.position_cd LEFT JOIN sy_code cd_vms ON cd_vms.code_grp = 'VENDOR_MEMBER_STATUS' AND cd_vms.code_value = u.vendor_user_status_cd
ORDER BY u.vendor_user_id ASC ORDER BY u.vendor_user_id DESC ORDER BY u.member_nm ASC ORDER BY u.member_nm DESC ORDER BY u.join_date ASC ORDER BY u.join_date DESC ORDER BY u.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

