UPDATE sy_vendor_user /* base.sy :: SyVendorUser :: updateSelective */
site_id = #{siteId}, vendor_id = #{vendorId}, user_id = #{userId}, member_nm = #{memberNm}, position_cd = #{positionCd}, vendor_user_dept_nm = #{vendorUserDeptNm}, vendor_user_phone = #{vendorUserPhone}, vendor_user_mobile = #{vendorUserMobile}, vendor_user_email = #{vendorUserEmail}, birth_date = #{birthDate}, is_main = #{isMain}, auth_yn = #{authYn}, join_date = #{joinDate}, leave_date = #{leaveDate}, vendor_user_status_cd = #{vendorUserStatusCd}, vendor_user_remark = #{vendorUserRemark}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE vendor_user_id = #{vendorUserId}
